window.BIBLE["Micah"] = {"1":{"chapter":"1","title":"JUDGMENT ON SAMARIA AND JUDAH","verses":{"1":{"text":"The word of the LORD that came to Micah the Morasthite in the days of Jotham, Ahaz, and Hezekiah, kings of Judah, which he saw concerning Samaria and Jerusalem.","ref":"Micah 1:1","synthesized":"This is the word of the LORD that came to Micah the Moreshite in the days of Jotham, Ahaz, and Hezekiah, kings of Judah—what he saw regarding Samaria and Jerusalem:","sources":{"KJV":{"text":"The word of the LORD that came to Micah the Morasthite in the days of Jotham, Ahaz, and Hezekiah, kings of Judah, which he saw concerning Samaria and Jerusalem."},"BSB":{"text":"This is the word of the LORD that came to Micah the Moreshite in the days of Jotham, Ahaz, and Hezekiah, kings of Judah—what he saw regarding Samaria and Jerusalem:"}},"definableWords":["word","LORD","days","kings","Judah","saw","Samaria","Jerusalem"],"peopleInVerse":[]},"2":{"text":"Hear, all ye people; hearken, O earth, and all that therein is: and let the Lord GOD be witness against you, the LORD from his holy temple.","ref":"Micah 1:2","synthesized":"Hear, O peoples, all of you; listen, O earth, and everyone in it! May the Lord GOD bear witness against you, the Lord from His holy temple.","sources":{"KJV":{"text":"Hear, all ye people; hearken, O earth, and all that therein is: and let the Lord GOD be witness against you, the LORD from his holy temple."},"BSB":{"text":"Hear, O peoples, all of you; listen, O earth, and everyone in it! May the Lord GOD bear witness against you, the Lord from His holy temple."}},"definableWords":["hear","earth","Lord","God","holy","temple"],"peopleInVerse":[]},"3":{"text":"For, behold, the LORD cometh forth out of his place, and will come down, and tread upon the high places of the earth.","ref":"Micah 1:3","synthesized":"For behold, the LORD comes forth from His dwelling place; He will come down and tread on the high places of the earth.","sources":{"KJV":{"text":"For, behold, the LORD cometh forth out of his place, and will come down, and tread upon the high places of the earth."},"BSB":{"text":"For behold, the LORD comes forth from His dwelling place; He will come down and tread on the high places of the earth."}},"definableWords":["LORD","earth"],"peopleInVerse":[]},"4":{"text":"And the mountains shall be molten under him, and the valleys shall be cleft, as wax before the fire, and as the waters that are poured down a steep place.","ref":"Micah 1:4","synthesized":"The mountains will melt beneath Him, and the valleys will split apart, like wax before the fire, like water rushing down a slope.","sources":{"KJV":{"text":"And the mountains shall be molten under him, and the valleys shall be cleft, as wax before the fire, and as the waters that are poured down a steep place."},"BSB":{"text":"The mountains will melt beneath Him, and the valleys will split apart, like wax before the fire, like water rushing down a slope."}},"definableWords":["water"],"peopleInVerse":[]},"5":{"text":"For the transgression of Jacob is all this, and for the sins of the house of Israel. What is the transgression of Jacob? is it not Samaria? and what are the high places of Judah? are they not Jerusalem?","ref":"Micah 1:5","synthesized":"All this is for the transgression of Jacob and the sins of the house of Israel. What is the transgression of Jacob? Is it not Samaria? And what is the high place of Judah? Is it not Jerusalem?","sources":{"KJV":{"text":"For the transgression of Jacob is all this, and for the sins of the house of Israel. What is the transgression of Jacob? is it not Samaria? and what are the high places of Judah? are they not Jerusalem?"},"BSB":{"text":"All this is for the transgression of Jacob and the sins of the house of Israel. What is the transgression of Jacob? Is it not Samaria? And what is the high place of Judah? Is it not Jerusalem?"}},"definableWords":["transgression","Jacob","house","Israel","Samaria","Judah","Jerusalem"],"peopleInVerse":["Jacob"]},"6":{"text":"Therefore I will make Samaria as an heap of the field, and as plantings of a vineyard: and I will pour down the stones thereof into the valley, and I will discover the foundations thereof.","ref":"Micah 1:6","synthesized":"Therefore I will make Samaria a heap of rubble in the open field, a planting area for a vineyard. I will pour her stones into the valley and expose her foundations.","sources":{"KJV":{"text":"Therefore I will make Samaria as an heap of the field, and as plantings of a vineyard: and I will pour down the stones thereof into the valley, and I will discover the foundations thereof."},"BSB":{"text":"Therefore I will make Samaria a heap of rubble in the open field, a planting area for a vineyard. I will pour her stones into the valley and expose her foundations."}},"definableWords":["make","Samaria","field"],"peopleInVerse":[]},"7":{"text":"And all the graven images thereof shall be beaten to pieces, and all the hires thereof shall be burned with the fire, and all the idols thereof will I lay desolate: for she gathered it of the hire of an harlot, and they shall return to the hire of an harlot.","ref":"Micah 1:7","synthesized":"All her carved images will be smashed to pieces; all her wages will be burned in the fire, and I will destroy all her idols. Since she collected the wages of a prostitute, they will be used again on a prostitute.","sources":{"KJV":{"text":"And all the graven images thereof shall be beaten to pieces, and all the hires thereof shall be burned with the fire, and all the idols thereof will I lay desolate: for she gathered it of the hire of an harlot, and they shall return to the hire of an harlot."},"BSB":{"text":"All her carved images will be smashed to pieces; all her wages will be burned in the fire, and I will destroy all her idols. Since she collected the wages of a prostitute, they will be used again on a prostitute."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Therefore I will wail and howl, I will go stripped and naked: I will make a wailing like the dragons, and mourning as the owls.","ref":"Micah 1:8","synthesized":"Because of this I will lament and wail; I will walk barefoot and naked. I will howl like a jackal and mourn like an ostrich.","sources":{"KJV":{"text":"Therefore I will wail and howl, I will go stripped and naked: I will make a wailing like the dragons, and mourning as the owls."},"BSB":{"text":"Because of this I will lament and wail; I will walk barefoot and naked. I will howl like a jackal and mourn like an ostrich."}},"definableWords":["walk","naked"],"peopleInVerse":[]},"9":{"text":"For her wound is incurable; for it is come unto Judah; he is come unto the gate of my people, even to Jerusalem.","ref":"Micah 1:9","synthesized":"For her wound is incurable; it has reached even Judah; it has approached the gate of my people, as far as Jerusalem itself.","sources":{"KJV":{"text":"For her wound is incurable; for it is come unto Judah; he is come unto the gate of my people, even to Jerusalem."},"BSB":{"text":"For her wound is incurable; it has reached even Judah; it has approached the gate of my people, as far as Jerusalem itself."}},"definableWords":["Judah","people","Jerusalem"],"peopleInVerse":[]},"10":{"text":"Declare ye it not at Gath, weep ye not at all: in the house of Aphrah roll thyself in the dust.","ref":"Micah 1:10","synthesized":"Do not tell it in Gath; do not weep at all. Roll in the dust in Beth-leaphrah.","sources":{"KJV":{"text":"Declare ye it not at Gath, weep ye not at all: in the house of Aphrah roll thyself in the dust."},"BSB":{"text":"Do not tell it in Gath; do not weep at all. Roll in the dust in Beth-leaphrah."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Pass ye away, thou inhabitant of Saphir, having thy shame naked: the inhabitant of Zaanan came not forth in the mourning of Bethezel; he shall receive of you his standing.","ref":"Micah 1:11","synthesized":"Depart in shameful nakedness, O dwellers of Shaphir. The dwellers of Zaanan will not come out. Beth-ezel is in mourning; its support is taken from you.","sources":{"KJV":{"text":"Pass ye away, thou inhabitant of Saphir, having thy shame naked: the inhabitant of Zaanan came not forth in the mourning of Bethezel; he shall receive of you his standing."},"BSB":{"text":"Depart in shameful nakedness, O dwellers of Shaphir. The dwellers of Zaanan will not come out. Beth-ezel is in mourning; its support is taken from you."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"For the inhabitant of Maroth waited carefully for good: but evil came down from the LORD unto the gate of Jerusalem.","ref":"Micah 1:12","synthesized":"For the dwellers of Maroth pined for good, but calamity came down from the LORD, even to the gate of Jerusalem.","sources":{"KJV":{"text":"For the inhabitant of Maroth waited carefully for good: but evil came down from the LORD unto the gate of Jerusalem."},"BSB":{"text":"For the dwellers of Maroth pined for good, but calamity came down from the LORD, even to the gate of Jerusalem."}},"definableWords":["good","LORD","Jerusalem"],"peopleInVerse":[]},"13":{"text":"O thou inhabitant of Lachish, bind the chariot to the swift beast: she is the beginning of the sin to the daughter of Zion: for the transgressions of Israel were found in thee.","ref":"Micah 1:13","synthesized":"Harness your chariot horses, O dweller of Lachish. You were the beginning of sin to the Daughter of Zion, for the transgressions of Israel were found in you.","sources":{"KJV":{"text":"O thou inhabitant of Lachish, bind the chariot to the swift beast: she is the beginning of the sin to the daughter of Zion: for the transgressions of Israel were found in thee."},"BSB":{"text":"Harness your chariot horses, O dweller of Lachish. You were the beginning of sin to the Daughter of Zion, for the transgressions of Israel were found in you."}},"definableWords":["beginning","sin","daughter","Zion","Israel"],"peopleInVerse":[]},"14":{"text":"Therefore shalt thou give presents to Moreshethgath: the houses of Achzib shall be a lie to the kings of Israel.","ref":"Micah 1:14","synthesized":"Therefore, send farewell gifts to Moresheth-gath; the houses of Achzib will prove deceptive to the kings of Israel.","sources":{"KJV":{"text":"Therefore shalt thou give presents to Moreshethgath: the houses of Achzib shall be a lie to the kings of Israel."},"BSB":{"text":"Therefore, send farewell gifts to Moresheth-gath; the houses of Achzib will prove deceptive to the kings of Israel."}},"definableWords":["kings","Israel"],"peopleInVerse":[]},"15":{"text":"Yet will I bring an heir unto thee, O inhabitant of Mareshah: he shall come unto Adullam the glory of Israel.","ref":"Micah 1:15","synthesized":"I will again bring a conqueror against you, O dweller of Mareshah. The glory of Israel will come to Adullam.","sources":{"KJV":{"text":"Yet will I bring an heir unto thee, O inhabitant of Mareshah: he shall come unto Adullam the glory of Israel."},"BSB":{"text":"I will again bring a conqueror against you, O dweller of Mareshah. The glory of Israel will come to Adullam."}},"definableWords":["glory","Israel"],"peopleInVerse":[]},"16":{"text":"Make thee bald, and poll thee for thy delicate children; enlarge thy baldness as the eagle; for they are gone into captivity from thee.","ref":"Micah 1:16","synthesized":"Shave yourselves bald and cut off your hair in mourning for your precious children; make yourselves as bald as an eagle, for they will go from you into exile.","sources":{"KJV":{"text":"Make thee bald, and poll thee for thy delicate children; enlarge thy baldness as the eagle; for they are gone into captivity from thee."},"BSB":{"text":"Shave yourselves bald and cut off your hair in mourning for your precious children; make yourselves as bald as an eagle, for they will go from you into exile."}},"definableWords":["make"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"WOE TO THEM THAT DEVISE INIQUITY","verses":{"1":{"text":"Woe to them that devise iniquity, and work evil upon their beds! when the morning is light, they practise it, because it is in the power of their hand.","ref":"Micah 2:1","synthesized":"Woe to those who devise iniquity and plot evil on their beds! At morning’s light they accomplish it because the power is in their hands.","sources":{"KJV":{"text":"Woe to them that devise iniquity, and work evil upon their beds! when the morning is light, they practise it, because it is in the power of their hand."},"BSB":{"text":"Woe to those who devise iniquity and plot evil on their beds! At morning’s light they accomplish it because the power is in their hands."}},"definableWords":["iniquity","evil","light"],"peopleInVerse":[]},"2":{"text":"And they covet fields, and take them by violence; and houses, and take them away: so they oppress a man and his house, even a man and his heritage.","ref":"Micah 2:2","synthesized":"They covet fields and seize them; they take away houses. They deprive a man of his home, a fellow man of his inheritance.","sources":{"KJV":{"text":"And they covet fields, and take them by violence; and houses, and take them away: so they oppress a man and his house, even a man and his heritage."},"BSB":{"text":"They covet fields and seize them; they take away houses. They deprive a man of his home, a fellow man of his inheritance."}},"definableWords":["man"],"peopleInVerse":[]},"3":{"text":"Therefore thus saith the LORD; Behold, against this family do I devise an evil, from which ye shall not remove your necks; neither shall ye go haughtily: for this time is evil.","ref":"Micah 2:3","synthesized":"Therefore this is what the LORD says:  “I am planning against this nation a disaster from which you cannot free your necks. Then you will not walk so proudly, for it will be a time of calamity.","sources":{"KJV":{"text":"Therefore thus saith the LORD; Behold, against this family do I devise an evil, from which ye shall not remove your necks; neither shall ye go haughtily: for this time is evil."},"BSB":{"text":"Therefore this is what the LORD says:  “I am planning against this nation a disaster from which you cannot free your necks. Then you will not walk so proudly, for it will be a time of calamity."}},"definableWords":["LORD","nation","walk"],"peopleInVerse":[]},"4":{"text":"In that day shall one take up a parable against you, and lament with a doleful lamentation, and say, We be utterly spoiled: he hath changed the portion of my people: how hath he removed it from me! turning away he hath divided our fields.","ref":"Micah 2:4","synthesized":"In that day they will take up a proverb against you and taunt you with this bitter lamentation: ‘We are utterly ruined! He has changed the portion of my people. How He has removed it from me! He has allotted our fields to traitors.’”","sources":{"KJV":{"text":"In that day shall one take up a parable against you, and lament with a doleful lamentation, and say, We be utterly spoiled: he hath changed the portion of my people: how hath he removed it from me! turning away he hath divided our fields."},"BSB":{"text":"In that day they will take up a proverb against you and taunt you with this bitter lamentation: ‘We are utterly ruined! He has changed the portion of my people. How He has removed it from me! He has allotted our fields to traitors.’”"}},"definableWords":["day","people"],"peopleInVerse":[]},"5":{"text":"Therefore thou shalt have none that shall cast a cord by lot in the congregation of the LORD.","ref":"Micah 2:5","synthesized":"Therefore, you will have no one in the assembly of the LORD to divide the land by lot.","sources":{"KJV":{"text":"Therefore thou shalt have none that shall cast a cord by lot in the congregation of the LORD."},"BSB":{"text":"Therefore, you will have no one in the assembly of the LORD to divide the land by lot."}},"definableWords":["one","LORD","land","Lot"],"peopleInVerse":[]},"6":{"text":"Prophesy ye not, say they to them that prophesy: they shall not prophesy to them, that they shall not take shame.","ref":"Micah 2:6","synthesized":"“Do not preach,” they preach. “Do not preach these things; disgrace will not overtake us.”","sources":{"KJV":{"text":"Prophesy ye not, say they to them that prophesy: they shall not prophesy to them, that they shall not take shame."},"BSB":{"text":"“Do not preach,” they preach. “Do not preach these things; disgrace will not overtake us.”"}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"O thou that art named the house of Jacob, is the spirit of the LORD straitened? are these his doings? do not my words do good to him that walketh uprightly?","ref":"Micah 2:7","synthesized":"Should it be said, O house of Jacob, “Is the Spirit of the LORD impatient? Are these the things He does?”   Do not My words bring good to him who walks uprightly?","sources":{"KJV":{"text":"O thou that art named the house of Jacob, is the spirit of the LORD straitened? are these his doings? do not my words do good to him that walketh uprightly?"},"BSB":{"text":"Should it be said, O house of Jacob, “Is the Spirit of the LORD impatient? Are these the things He does?”   Do not My words bring good to him who walks uprightly?"}},"definableWords":["house","Jacob","Spirit","LORD","good"],"peopleInVerse":["Jacob"]},"8":{"text":"Even of late my people is risen up as an enemy: ye pull off the robe with the garment from them that pass by securely as men averse from war.","ref":"Micah 2:8","synthesized":"But of late My people have risen up like an enemy: You strip off the splendid robe from unsuspecting passersby like men returning from battle.","sources":{"KJV":{"text":"Even of late my people is risen up as an enemy: ye pull off the robe with the garment from them that pass by securely as men averse from war."},"BSB":{"text":"But of late My people have risen up like an enemy: You strip off the splendid robe from unsuspecting passersby like men returning from battle."}},"definableWords":["people","men"],"peopleInVerse":[]},"9":{"text":"The women of my people have ye cast out from their pleasant houses; from their children have ye taken away my glory for ever.","ref":"Micah 2:9","synthesized":"You drive the women of My people from their pleasant homes. You take away My blessing from their children forever.","sources":{"KJV":{"text":"The women of my people have ye cast out from their pleasant houses; from their children have ye taken away my glory for ever."},"BSB":{"text":"You drive the women of My people from their pleasant homes. You take away My blessing from their children forever."}},"definableWords":["women","people","blessing"],"peopleInVerse":[]},"10":{"text":"Arise ye, and depart; for this is not your rest: because it is polluted, it shall destroy you, even with a sore destruction.","ref":"Micah 2:10","synthesized":"Arise and depart, for this is not your place of rest, because its defilement brings destruction— a grievous destruction!","sources":{"KJV":{"text":"Arise ye, and depart; for this is not your rest: because it is polluted, it shall destroy you, even with a sore destruction."},"BSB":{"text":"Arise and depart, for this is not your place of rest, because its defilement brings destruction— a grievous destruction!"}},"definableWords":["rest"],"peopleInVerse":[]},"11":{"text":"If a man walking in the spirit and falsehood do lie, saying, I will prophesy unto thee of wine and of strong drink; he shall even be the prophet of this people.","ref":"Micah 2:11","synthesized":"If a man of wind were to come and say falsely, “I will preach to you of wine and strong drink,” he would be just the preacher for this people!","sources":{"KJV":{"text":"If a man walking in the spirit and falsehood do lie, saying, I will prophesy unto thee of wine and of strong drink; he shall even be the prophet of this people."},"BSB":{"text":"If a man of wind were to come and say falsely, “I will preach to you of wine and strong drink,” he would be just the preacher for this people!"}},"definableWords":["man","strong","people"],"peopleInVerse":[]},"12":{"text":"I will surely assemble, O Jacob, all of thee; I will surely gather the remnant of Israel; I will put them together as the sheep of Bozrah, as the flock in the midst of their fold: they shall make great noise by reason of the multitude of men.","ref":"Micah 2:12","synthesized":"I will surely gather all of you, O Jacob; I will collect the remnant of Israel. I will bring them together like sheep in a pen, like a flock in the midst of its pasture— a noisy throng.","sources":{"KJV":{"text":"I will surely assemble, O Jacob, all of thee; I will surely gather the remnant of Israel; I will put them together as the sheep of Bozrah, as the flock in the midst of their fold: they shall make great noise by reason of the multitude of men."},"BSB":{"text":"I will surely gather all of you, O Jacob; I will collect the remnant of Israel. I will bring them together like sheep in a pen, like a flock in the midst of its pasture— a noisy throng."}},"definableWords":["Jacob","remnant","Israel"],"peopleInVerse":["Jacob"]},"13":{"text":"The breaker is come up before them: they have broken up, and have passed through the gate, and are gone out by it: and their king shall pass before them, and the LORD on the head of them.","ref":"Micah 2:13","synthesized":"One who breaks open the way will go up before them; they will break through the gate, and go out by it. Their King will pass through before them, the LORD as their leader.","sources":{"KJV":{"text":"The breaker is come up before them: they have broken up, and have passed through the gate, and are gone out by it: and their king shall pass before them, and the LORD on the head of them."},"BSB":{"text":"One who breaks open the way will go up before them; they will break through the gate, and go out by it. Their King will pass through before them, the LORD as their leader."}},"definableWords":["one","way","King","LORD"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"THE PROPHETS THAT MAKE MY PEOPLE ERR","verses":{"1":{"text":"And I said, Hear, I pray you, O heads of Jacob, and ye princes of the house of Israel; Is it not for you to know judgment?","ref":"Micah 3:1","synthesized":"Then I said:  “Hear now, O leaders of Jacob, you rulers of the house of Israel. Should you not know justice?","sources":{"KJV":{"text":"And I said, Hear, I pray you, O heads of Jacob, and ye princes of the house of Israel; Is it not for you to know judgment?"},"BSB":{"text":"Then I said:  “Hear now, O leaders of Jacob, you rulers of the house of Israel. Should you not know justice?"}},"definableWords":["hear","Jacob","house","Israel","justice"],"peopleInVerse":["Jacob"]},"2":{"text":"Who hate the good, and love the evil; who pluck off their skin from off them, and their flesh from off their bones;","ref":"Micah 3:2","synthesized":"You hate good and love evil. You tear the skin from my people and strip the flesh from their bones.","sources":{"KJV":{"text":"Who hate the good, and love the evil; who pluck off their skin from off them, and their flesh from off their bones;"},"BSB":{"text":"You hate good and love evil. You tear the skin from my people and strip the flesh from their bones."}},"definableWords":["good","love","evil","people","flesh","bones"],"peopleInVerse":[]},"3":{"text":"Who also eat the flesh of my people, and flay their skin from off them; and they break their bones, and chop them in pieces, as for the pot, and as flesh within the caldron.","ref":"Micah 3:3","synthesized":"You eat the flesh of my people after stripping off their skin and breaking their bones. You chop them up like flesh for the cooking pot, like meat in a cauldron.”","sources":{"KJV":{"text":"Who also eat the flesh of my people, and flay their skin from off them; and they break their bones, and chop them in pieces, as for the pot, and as flesh within the caldron."},"BSB":{"text":"You eat the flesh of my people after stripping off their skin and breaking their bones. You chop them up like flesh for the cooking pot, like meat in a cauldron.”"}},"definableWords":["flesh","people","bones"],"peopleInVerse":[]},"4":{"text":"Then shall they cry unto the LORD, but he will not hear them: he will even hide his face from them at that time, as they have behaved themselves ill in their doings.","ref":"Micah 3:4","synthesized":"Then they will cry out to the LORD, but He will not answer them. At that time He will hide His face from them because of the evil they have done.","sources":{"KJV":{"text":"Then shall they cry unto the LORD, but he will not hear them: he will even hide his face from them at that time, as they have behaved themselves ill in their doings."},"BSB":{"text":"Then they will cry out to the LORD, but He will not answer them. At that time He will hide His face from them because of the evil they have done."}},"definableWords":["LORD","evil"],"peopleInVerse":[]},"5":{"text":"Thus saith the LORD concerning the prophets that make my people err, that bite with their teeth, and cry, Peace; and he that putteth not into their mouths, they even prepare war against him.","ref":"Micah 3:5","synthesized":"This is what the LORD says:  “As for the prophets who lead My people astray, who proclaim peace while they chew with their teeth, but declare war against one who puts nothing in their mouths:","sources":{"KJV":{"text":"Thus saith the LORD concerning the prophets that make my people err, that bite with their teeth, and cry, Peace; and he that putteth not into their mouths, they even prepare war against him."},"BSB":{"text":"This is what the LORD says:  “As for the prophets who lead My people astray, who proclaim peace while they chew with their teeth, but declare war against one who puts nothing in their mouths:"}},"definableWords":["LORD","people","peace","one"],"peopleInVerse":[]},"6":{"text":"Therefore night shall be unto you, that ye shall not have a vision; and it shall be dark unto you, that ye shall not divine; and the sun shall go down over the prophets, and the day shall be dark over them.","ref":"Micah 3:6","synthesized":"Therefore night will come over you without visions, and darkness without divination. The sun will set on these prophets, and the daylight will turn black over them.","sources":{"KJV":{"text":"Therefore night shall be unto you, that ye shall not have a vision; and it shall be dark unto you, that ye shall not divine; and the sun shall go down over the prophets, and the day shall be dark over them."},"BSB":{"text":"Therefore night will come over you without visions, and darkness without divination. The sun will set on these prophets, and the daylight will turn black over them."}},"definableWords":["night","darkness"],"peopleInVerse":[]},"7":{"text":"Then shall the seers be ashamed, and the diviners confounded: yea, they shall all cover their lips; for there is no answer of God.","ref":"Micah 3:7","synthesized":"Then the seers will be ashamed and the diviners will be disgraced. They will all cover their mouths because there is no answer from God.”","sources":{"KJV":{"text":"Then shall the seers be ashamed, and the diviners confounded: yea, they shall all cover their lips; for there is no answer of God."},"BSB":{"text":"Then the seers will be ashamed and the diviners will be disgraced. They will all cover their mouths because there is no answer from God.”"}},"definableWords":["God"],"peopleInVerse":[]},"8":{"text":"But truly I am full of power by the spirit of the LORD, and of judgment, and of might, to declare unto Jacob his transgression, and to Israel his sin.","ref":"Micah 3:8","synthesized":"As for me, however, I am filled with power by the Spirit of the LORD, with justice and courage, to declare to Jacob his transgression and to Israel his sin.","sources":{"KJV":{"text":"But truly I am full of power by the spirit of the LORD, and of judgment, and of might, to declare unto Jacob his transgression, and to Israel his sin."},"BSB":{"text":"As for me, however, I am filled with power by the Spirit of the LORD, with justice and courage, to declare to Jacob his transgression and to Israel his sin."}},"definableWords":["Spirit","LORD","justice","Jacob","transgression","Israel","sin"],"peopleInVerse":["Jacob"]},"9":{"text":"Hear this, I pray you, ye heads of the house of Jacob, and princes of the house of Israel, that abhor judgment, and pervert all equity.","ref":"Micah 3:9","synthesized":"Now hear this, O leaders of the house of Jacob and rulers of the house of Israel, who despise justice and pervert all that is right,","sources":{"KJV":{"text":"Hear this, I pray you, ye heads of the house of Jacob, and princes of the house of Israel, that abhor judgment, and pervert all equity."},"BSB":{"text":"Now hear this, O leaders of the house of Jacob and rulers of the house of Israel, who despise justice and pervert all that is right,"}},"definableWords":["hear","house","Jacob","Israel","justice"],"peopleInVerse":["Jacob"]},"10":{"text":"They build up Zion with blood, and Jerusalem with iniquity.","ref":"Micah 3:10","synthesized":"who build Zion with bloodshed and Jerusalem with iniquity.","sources":{"KJV":{"text":"They build up Zion with blood, and Jerusalem with iniquity."},"BSB":{"text":"who build Zion with bloodshed and Jerusalem with iniquity."}},"definableWords":["Zion","Jerusalem","iniquity"],"peopleInVerse":[]},"11":{"text":"The heads thereof judge for reward, and the priests thereof teach for hire, and the prophets thereof divine for money: yet will they lean upon the LORD, and say, Is not the LORD among us? none evil can come upon us.","ref":"Micah 3:11","synthesized":"Her leaders judge for a bribe, her priests teach for a price, and her prophets practice divination for money. Yet they lean upon the LORD, saying, “Is not the LORD among us? No disaster can come upon us.”","sources":{"KJV":{"text":"The heads thereof judge for reward, and the priests thereof teach for hire, and the prophets thereof divine for money: yet will they lean upon the LORD, and say, Is not the LORD among us? none evil can come upon us."},"BSB":{"text":"Her leaders judge for a bribe, her priests teach for a price, and her prophets practice divination for money. Yet they lean upon the LORD, saying, “Is not the LORD among us? No disaster can come upon us.”"}},"definableWords":["LORD","Lord"],"peopleInVerse":[]},"12":{"text":"Therefore shall Zion for your sake be plowed as a field, and Jerusalem shall become heaps, and the mountain of the house as the high places of the forest.","ref":"Micah 3:12","synthesized":"Therefore, because of you, Zion will be plowed like a field, Jerusalem will become a heap of rubble, and the temple mount a wooded ridge.","sources":{"KJV":{"text":"Therefore shall Zion for your sake be plowed as a field, and Jerusalem shall become heaps, and the mountain of the house as the high places of the forest."},"BSB":{"text":"Therefore, because of you, Zion will be plowed like a field, Jerusalem will become a heap of rubble, and the temple mount a wooded ridge."}},"definableWords":["Zion","field","Jerusalem","temple"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"MOUNTAIN OF THE LORD'S HOUSE","verses":{"1":{"text":"But in the last days it shall come to pass, that the mountain of the house of the LORD shall be established in the top of the mountains, and it shall be exalted above the hills; and people shall flow unto it.","ref":"Micah 4:1","synthesized":"In the last days the mountain of the house of the LORD will be established as the chief of the mountains; it will be raised above the hills, and the peoples will stream to it.","sources":{"KJV":{"text":"But in the last days it shall come to pass, that the mountain of the house of the LORD shall be established in the top of the mountains, and it shall be exalted above the hills; and people shall flow unto it."},"BSB":{"text":"In the last days the mountain of the house of the LORD will be established as the chief of the mountains; it will be raised above the hills, and the peoples will stream to it."}},"definableWords":["days","house","LORD"],"peopleInVerse":[]},"2":{"text":"And many nations shall come, and say, Come, and let us go up to the mountain of the LORD, and to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths: for the law shall go forth of Zion, and the word of the LORD from Jerusalem.","ref":"Micah 4:2","synthesized":"And many nations will come and say:   “Come, let us go up to the mountain of the LORD, to the house of the God of Jacob. He will teach us His ways, so that we may walk in His paths.”   For the law will go forth from Zion and the word of the LORD from Jerusalem.","sources":{"KJV":{"text":"And many nations shall come, and say, Come, and let us go up to the mountain of the LORD, and to the house of the God of Jacob; and he will teach us of his ways, and we will walk in his paths: for the law shall go forth of Zion, and the word of the LORD from Jerusalem."},"BSB":{"text":"And many nations will come and say:   “Come, let us go up to the mountain of the LORD, to the house of the God of Jacob. He will teach us His ways, so that we may walk in His paths.”   For the law will go forth from Zion and the word of the LORD from Jerusalem."}},"definableWords":["nations","LORD","house","God","Jacob","walk","law","Zion","word","Lord","Jerusalem"],"peopleInVerse":["Jacob"]},"3":{"text":"And he shall judge among many people, and rebuke strong nations afar off; and they shall beat their swords into plowshares, and their spears into pruninghooks: nation shall not lift up a sword against nation, neither shall they learn war any more.","ref":"Micah 4:3","synthesized":"Then He will judge between many peoples and arbitrate for strong nations far and wide. Then they will beat their swords into plowshares and their spears into pruning hooks. Nation will no longer take up the sword against nation, nor will they train anymore for war.","sources":{"KJV":{"text":"And he shall judge among many people, and rebuke strong nations afar off; and they shall beat their swords into plowshares, and their spears into pruninghooks: nation shall not lift up a sword against nation, neither shall they learn war any more."},"BSB":{"text":"Then He will judge between many peoples and arbitrate for strong nations far and wide. Then they will beat their swords into plowshares and their spears into pruning hooks. Nation will no longer take up the sword against nation, nor will they train anymore for war."}},"definableWords":["strong","nations","nation"],"peopleInVerse":[]},"4":{"text":"But they shall sit every man under his vine and under his fig tree; and none shall make them afraid: for the mouth of the LORD of hosts hath spoken it.","ref":"Micah 4:4","synthesized":"And each man will sit under his own vine and under his own fig tree, with no one to frighten him. For the mouth of the LORD of Hosts has spoken.","sources":{"KJV":{"text":"But they shall sit every man under his vine and under his fig tree; and none shall make them afraid: for the mouth of the LORD of hosts hath spoken it."},"BSB":{"text":"And each man will sit under his own vine and under his own fig tree, with no one to frighten him. For the mouth of the LORD of Hosts has spoken."}},"definableWords":["man","tree","one","LORD"],"peopleInVerse":[]},"5":{"text":"For all people will walk every one in the name of his god, and we will walk in the name of the LORD our God for ever and ever.","ref":"Micah 4:5","synthesized":"Though each of the peoples may walk in the name of his god, yet we will walk in the name of the LORD our God forever and ever.","sources":{"KJV":{"text":"For all people will walk every one in the name of his god, and we will walk in the name of the LORD our God for ever and ever."},"BSB":{"text":"Though each of the peoples may walk in the name of his god, yet we will walk in the name of the LORD our God forever and ever."}},"definableWords":["walk","name","God","LORD"],"peopleInVerse":[]},"6":{"text":"In that day, saith the LORD, will I assemble her that halteth, and I will gather her that is driven out, and her that I have afflicted;","ref":"Micah 4:6","synthesized":"“On that day,” declares the LORD, “I will gather the lame; I will assemble the outcast, even those whom I have afflicted.","sources":{"KJV":{"text":"In that day, saith the LORD, will I assemble her that halteth, and I will gather her that is driven out, and her that I have afflicted;"},"BSB":{"text":"“On that day,” declares the LORD, “I will gather the lame; I will assemble the outcast, even those whom I have afflicted."}},"definableWords":["day","LORD"],"peopleInVerse":[]},"7":{"text":"And I will make her that halted a remnant, and her that was cast far off a strong nation: and the LORD shall reign over them in mount Zion from henceforth, even for ever.","ref":"Micah 4:7","synthesized":"And I will make the lame into a remnant, and the outcast into a strong nation. Then the LORD will rule over them in Mount Zion from that day and forever.","sources":{"KJV":{"text":"And I will make her that halted a remnant, and her that was cast far off a strong nation: and the LORD shall reign over them in mount Zion from henceforth, even for ever."},"BSB":{"text":"And I will make the lame into a remnant, and the outcast into a strong nation. Then the LORD will rule over them in Mount Zion from that day and forever."}},"definableWords":["make","remnant","strong","nation","LORD","rule","Zion","day"],"peopleInVerse":[]},"8":{"text":"And thou, O tower of the flock, the strong hold of the daughter of Zion, unto thee shall it come, even the first dominion; the kingdom shall come to the daughter of Jerusalem.","ref":"Micah 4:8","synthesized":"And you, O watchtower of the flock, O stronghold of the Daughter of Zion— the former dominion will be restored to you; sovereignty will come to the Daughter of Jerusalem.”","sources":{"KJV":{"text":"And thou, O tower of the flock, the strong hold of the daughter of Zion, unto thee shall it come, even the first dominion; the kingdom shall come to the daughter of Jerusalem."},"BSB":{"text":"And you, O watchtower of the flock, O stronghold of the Daughter of Zion— the former dominion will be restored to you; sovereignty will come to the Daughter of Jerusalem.”"}},"definableWords":["daughter","Zion","dominion","Jerusalem"],"peopleInVerse":[]},"9":{"text":"Now why dost thou cry out aloud? is there no king in thee? is thy counsellor perished? for pangs have taken thee as a woman in travail.","ref":"Micah 4:9","synthesized":"Why do you now cry aloud? Is there no king among you? Has your counselor perished so that anguish grips you like a woman in labor?","sources":{"KJV":{"text":"Now why dost thou cry out aloud? is there no king in thee? is thy counsellor perished? for pangs have taken thee as a woman in travail."},"BSB":{"text":"Why do you now cry aloud? Is there no king among you? Has your counselor perished so that anguish grips you like a woman in labor?"}},"definableWords":["king","woman"],"peopleInVerse":[]},"10":{"text":"Be in pain, and labour to bring forth, O daughter of Zion, like a woman in travail: for now shalt thou go forth out of the city, and thou shalt dwell in the field, and thou shalt go even to Babylon; there shalt thou be delivered; there the LORD shall redeem thee from the hand of thine enemies.","ref":"Micah 4:10","synthesized":"Writhe in agony, O Daughter of Zion, like a woman in labor. For now you will leave the city and camp in the open fields. You will go to Babylon; there you will be rescued; there the LORD will redeem you from the hand of your enemies!","sources":{"KJV":{"text":"Be in pain, and labour to bring forth, O daughter of Zion, like a woman in travail: for now shalt thou go forth out of the city, and thou shalt dwell in the field, and thou shalt go even to Babylon; there shalt thou be delivered; there the LORD shall redeem thee from the hand of thine enemies."},"BSB":{"text":"Writhe in agony, O Daughter of Zion, like a woman in labor. For now you will leave the city and camp in the open fields. You will go to Babylon; there you will be rescued; there the LORD will redeem you from the hand of your enemies!"}},"definableWords":["daughter","Zion","woman","Babylon","LORD"],"peopleInVerse":[]},"11":{"text":"Now also many nations are gathered against thee, that say, Let her be defiled, and let our eye look upon Zion.","ref":"Micah 4:11","synthesized":"But now many nations have assembled against you, saying, “Let her be defiled, and let us feast our eyes on Zion.”","sources":{"KJV":{"text":"Now also many nations are gathered against thee, that say, Let her be defiled, and let our eye look upon Zion."},"BSB":{"text":"But now many nations have assembled against you, saying, “Let her be defiled, and let us feast our eyes on Zion.”"}},"definableWords":["nations","Zion"],"peopleInVerse":[]},"12":{"text":"But they know not the thoughts of the LORD, neither understand they his counsel: for he shall gather them as the sheaves into the floor.","ref":"Micah 4:12","synthesized":"But they do not know the thoughts of the LORD or understand His plan, for He has gathered them like sheaves to the threshing floor.","sources":{"KJV":{"text":"But they know not the thoughts of the LORD, neither understand they his counsel: for he shall gather them as the sheaves into the floor."},"BSB":{"text":"But they do not know the thoughts of the LORD or understand His plan, for He has gathered them like sheaves to the threshing floor."}},"definableWords":["LORD","or"],"peopleInVerse":[]},"13":{"text":"Arise and thresh, O daughter of Zion: for I will make thine horn iron, and I will make thy hoofs brass: and thou shalt beat in pieces many people: and I will consecrate their gain unto the LORD, and their substance unto the Lord of the whole earth.","ref":"Micah 4:13","synthesized":"Rise and thresh, O Daughter of Zion, for I will give you horns of iron and hooves of bronze to break to pieces many peoples. Then you will devote their gain to the LORD, their wealth to the Lord of all the earth.","sources":{"KJV":{"text":"Arise and thresh, O daughter of Zion: for I will make thine horn iron, and I will make thy hoofs brass: and thou shalt beat in pieces many people: and I will consecrate their gain unto the LORD, and their substance unto the Lord of the whole earth."},"BSB":{"text":"Rise and thresh, O Daughter of Zion, for I will give you horns of iron and hooves of bronze to break to pieces many peoples. Then you will devote their gain to the LORD, their wealth to the Lord of all the earth."}},"definableWords":["daughter","Zion","LORD","Lord","earth"],"peopleInVerse":[]}}},"5":{"chapter":"5","title":"BETHLEHEM — THE MESSIAH'S BIRTHPLACE","verses":{"1":{"text":"Now gather thyself in troops, O daughter of troops: he hath laid siege against us: they shall smite the judge of Israel with a rod upon the cheek.","ref":"Micah 5:1","synthesized":"Now, O daughter of troops, mobilize your troops; for a siege is laid against us! With a rod they will strike the cheek of the judge of Israel.","sources":{"KJV":{"text":"Now gather thyself in troops, O daughter of troops: he hath laid siege against us: they shall smite the judge of Israel with a rod upon the cheek."},"BSB":{"text":"Now, O daughter of troops, mobilize your troops; for a siege is laid against us! With a rod they will strike the cheek of the judge of Israel."}},"definableWords":["daughter","Israel"],"peopleInVerse":[]},"2":{"text":"But thou, Bethlehem Ephratah, though thou be little among the thousands of Judah, yet out of thee shall he come forth unto me that is to be ruler in Israel; whose goings forth have been from of old, from everlasting.","ref":"Micah 5:2","synthesized":"But you, Bethlehem Ephrathah, who are small among the clans of Judah, out of you will come forth for Me One to be ruler over Israel— One whose origins are of old, from the days of eternity.","sources":{"KJV":{"text":"But thou, Bethlehem Ephratah, though thou be little among the thousands of Judah, yet out of thee shall he come forth unto me that is to be ruler in Israel; whose goings forth have been from of old, from everlasting."},"BSB":{"text":"But you, Bethlehem Ephrathah, who are small among the clans of Judah, out of you will come forth for Me One to be ruler over Israel— One whose origins are of old, from the days of eternity."}},"definableWords":["Judah","one","ruler","Israel","days"],"peopleInVerse":[]},"3":{"text":"Therefore will he give them up, until the time that she which travaileth hath brought forth: then the remnant of his brethren shall return unto the children of Israel.","ref":"Micah 5:3","synthesized":"Therefore Israel will be abandoned until she who is in labor has given birth; then the rest of His brothers will return to the children of Israel.","sources":{"KJV":{"text":"Therefore will he give them up, until the time that she which travaileth hath brought forth: then the remnant of his brethren shall return unto the children of Israel."},"BSB":{"text":"Therefore Israel will be abandoned until she who is in labor has given birth; then the rest of His brothers will return to the children of Israel."}},"definableWords":["Israel","rest"],"peopleInVerse":[]},"4":{"text":"And he shall stand and feed in the strength of the LORD, in the majesty of the name of the LORD his God; and they shall abide: for now shall he be great unto the ends of the earth.","ref":"Micah 5:4","synthesized":"He will stand and shepherd His flock in the strength of the LORD, in the majestic name of the LORD His God. And they will dwell securely, for then His greatness will extend to the ends of the earth.","sources":{"KJV":{"text":"And he shall stand and feed in the strength of the LORD, in the majesty of the name of the LORD his God; and they shall abide: for now shall he be great unto the ends of the earth."},"BSB":{"text":"He will stand and shepherd His flock in the strength of the LORD, in the majestic name of the LORD His God. And they will dwell securely, for then His greatness will extend to the ends of the earth."}},"definableWords":["stand","shepherd","LORD","name","Lord","God","earth"],"peopleInVerse":[]},"5":{"text":"And this man shall be the peace, when the Assyrian shall come into our land: and when he shall tread in our palaces, then shall we raise against him seven shepherds, and eight principal men.","ref":"Micah 5:5","synthesized":"And He will be our peace when Assyria invades our land and tramples our citadels. We will raise against it seven shepherds, even eight leaders of men.","sources":{"KJV":{"text":"And this man shall be the peace, when the Assyrian shall come into our land: and when he shall tread in our palaces, then shall we raise against him seven shepherds, and eight principal men."},"BSB":{"text":"And He will be our peace when Assyria invades our land and tramples our citadels. We will raise against it seven shepherds, even eight leaders of men."}},"definableWords":["peace","land","men"],"peopleInVerse":[]},"6":{"text":"And they shall waste the land of Assyria with the sword, and the land of Nimrod in the entrances thereof: thus shall he deliver us from the Assyrian, when he cometh into our land, and when he treadeth within our borders.","ref":"Micah 5:6","synthesized":"And they will rule the land of Assyria with the sword, and the land of Nimrod with the blade drawn. So He will deliver us when Assyria invades our land and marches into our borders.","sources":{"KJV":{"text":"And they shall waste the land of Assyria with the sword, and the land of Nimrod in the entrances thereof: thus shall he deliver us from the Assyrian, when he cometh into our land, and when he treadeth within our borders."},"BSB":{"text":"And they will rule the land of Assyria with the sword, and the land of Nimrod with the blade drawn. So He will deliver us when Assyria invades our land and marches into our borders."}},"definableWords":["rule","land","deliver"],"peopleInVerse":[]},"7":{"text":"And the remnant of Jacob shall be in the midst of many people as a dew from the LORD, as the showers upon the grass, that tarrieth not for man, nor waiteth for the sons of men.","ref":"Micah 5:7","synthesized":"Then the remnant of Jacob will be in the midst of many peoples like dew from the LORD, like showers on the grass, which do not wait for man or linger for mankind.","sources":{"KJV":{"text":"And the remnant of Jacob shall be in the midst of many people as a dew from the LORD, as the showers upon the grass, that tarrieth not for man, nor waiteth for the sons of men."},"BSB":{"text":"Then the remnant of Jacob will be in the midst of many peoples like dew from the LORD, like showers on the grass, which do not wait for man or linger for mankind."}},"definableWords":["remnant","Jacob","LORD","wait","man","or"],"peopleInVerse":["Jacob"]},"8":{"text":"And the remnant of Jacob shall be among the Gentiles in the midst of many people as a lion among the beasts of the forest, as a young lion among the flocks of sheep: who, if he go through, both treadeth down, and teareth in pieces, and none can deliver.","ref":"Micah 5:8","synthesized":"Then the remnant of Jacob will be among the nations, in the midst of many peoples, like a lion among the beasts of the forest, like a young lion among flocks of sheep, which tramples and tears as it passes through, with no one to rescue them.","sources":{"KJV":{"text":"And the remnant of Jacob shall be among the Gentiles in the midst of many people as a lion among the beasts of the forest, as a young lion among the flocks of sheep: who, if he go through, both treadeth down, and teareth in pieces, and none can deliver."},"BSB":{"text":"Then the remnant of Jacob will be among the nations, in the midst of many peoples, like a lion among the beasts of the forest, like a young lion among flocks of sheep, which tramples and tears as it passes through, with no one to rescue them."}},"definableWords":["remnant","Jacob","nations","lion","one"],"peopleInVerse":["Jacob"]},"9":{"text":"Thine hand shall be lifted up upon thine adversaries, and all thine enemies shall be cut off.","ref":"Micah 5:9","synthesized":"Your hand will be lifted over your foes, and all your enemies will be cut off.","sources":{"KJV":{"text":"Thine hand shall be lifted up upon thine adversaries, and all thine enemies shall be cut off."},"BSB":{"text":"Your hand will be lifted over your foes, and all your enemies will be cut off."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"And it shall come to pass in that day, saith the LORD, that I will cut off thy horses out of the midst of thee, and I will destroy thy chariots:","ref":"Micah 5:10","synthesized":"“In that day,” declares the LORD, “I will remove your horses from among you and wreck your chariots.","sources":{"KJV":{"text":"And it shall come to pass in that day, saith the LORD, that I will cut off thy horses out of the midst of thee, and I will destroy thy chariots:"},"BSB":{"text":"“In that day,” declares the LORD, “I will remove your horses from among you and wreck your chariots."}},"definableWords":["day","LORD"],"peopleInVerse":[]},"11":{"text":"And I will cut off the cities of thy land, and throw down all thy strong holds:","ref":"Micah 5:11","synthesized":"I will remove the cities of your land and tear down all your strongholds.","sources":{"KJV":{"text":"And I will cut off the cities of thy land, and throw down all thy strong holds:"},"BSB":{"text":"I will remove the cities of your land and tear down all your strongholds."}},"definableWords":["land"],"peopleInVerse":[]},"12":{"text":"And I will cut off witchcrafts out of thine hand; and thou shalt have no more soothsayers:","ref":"Micah 5:12","synthesized":"I will cut the sorceries from your hand, and you will have no fortune-tellers.","sources":{"KJV":{"text":"And I will cut off witchcrafts out of thine hand; and thou shalt have no more soothsayers:"},"BSB":{"text":"I will cut the sorceries from your hand, and you will have no fortune-tellers."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Thy graven images also will I cut off, and thy standing images out of the midst of thee; and thou shalt no more worship the work of thine hands.","ref":"Micah 5:13","synthesized":"I will also cut off the carved images and sacred pillars from among you, so that you will no longer bow down to the work of your own hands.","sources":{"KJV":{"text":"Thy graven images also will I cut off, and thy standing images out of the midst of thee; and thou shalt no more worship the work of thine hands."},"BSB":{"text":"I will also cut off the carved images and sacred pillars from among you, so that you will no longer bow down to the work of your own hands."}},"definableWords":["work"],"peopleInVerse":[]},"14":{"text":"And I will pluck up thy groves out of the midst of thee: so will I destroy thy cities.","ref":"Micah 5:14","synthesized":"I will root out the Asherah poles from your midst and demolish your cities.","sources":{"KJV":{"text":"And I will pluck up thy groves out of the midst of thee: so will I destroy thy cities."},"BSB":{"text":"I will root out the Asherah poles from your midst and demolish your cities."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"And I will execute vengeance in anger and fury upon the heathen, such as they have not heard.","ref":"Micah 5:15","synthesized":"I will take vengeance in anger and wrath upon the nations that have not obeyed Me.”","sources":{"KJV":{"text":"And I will execute vengeance in anger and fury upon the heathen, such as they have not heard."},"BSB":{"text":"I will take vengeance in anger and wrath upon the nations that have not obeyed Me.”"}},"definableWords":["anger","wrath","nations"],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"WHAT DOTH THE LORD REQUIRE","verses":{"1":{"text":"Hear ye now what the LORD saith; Arise, contend thou before the mountains, and let the hills hear thy voice.","ref":"Micah 6:1","synthesized":"Hear now what the LORD says:  “Arise, plead your case before the mountains, and let the hills hear your voice.","sources":{"KJV":{"text":"Hear ye now what the LORD saith; Arise, contend thou before the mountains, and let the hills hear thy voice."},"BSB":{"text":"Hear now what the LORD says:  “Arise, plead your case before the mountains, and let the hills hear your voice."}},"definableWords":["hear","LORD","voice"],"peopleInVerse":[]},"2":{"text":"Hear ye, O mountains, the LORD’s controversy, and ye strong foundations of the earth: for the LORD hath a controversy with his people, and he will plead with Israel.","ref":"Micah 6:2","synthesized":"Hear, O mountains, the LORD’s indictment, you enduring foundations of the earth. For the LORD has a case against His people, and He will argue it against Israel:","sources":{"KJV":{"text":"Hear ye, O mountains, the LORD’s controversy, and ye strong foundations of the earth: for the LORD hath a controversy with his people, and he will plead with Israel."},"BSB":{"text":"Hear, O mountains, the LORD’s indictment, you enduring foundations of the earth. For the LORD has a case against His people, and He will argue it against Israel:"}},"definableWords":["hear","LORD","earth","Lord","people","Israel"],"peopleInVerse":[]},"3":{"text":"O my people, what have I done unto thee? and wherein have I wearied thee? testify against me.","ref":"Micah 6:3","synthesized":"‘My people, what have I done to you? Testify against Me how I have wearied you!","sources":{"KJV":{"text":"O my people, what have I done unto thee? and wherein have I wearied thee? testify against me."},"BSB":{"text":"‘My people, what have I done to you? Testify against Me how I have wearied you!"}},"definableWords":["people"],"peopleInVerse":[]},"4":{"text":"For I brought thee up out of the land of Egypt, and redeemed thee out of the house of servants; and I sent before thee Moses, Aaron, and Miriam.","ref":"Micah 6:4","synthesized":"For I brought you up from the land of Egypt and redeemed you from the house of slavery. I sent Moses before you, as well as Aaron and Miriam.","sources":{"KJV":{"text":"For I brought thee up out of the land of Egypt, and redeemed thee out of the house of servants; and I sent before thee Moses, Aaron, and Miriam."},"BSB":{"text":"For I brought you up from the land of Egypt and redeemed you from the house of slavery. I sent Moses before you, as well as Aaron and Miriam."}},"definableWords":["land","Egypt","house"],"peopleInVerse":["Moses","Aaron","Miriam"]},"5":{"text":"O my people, remember now what Balak king of Moab consulted, and what Balaam the son of Beor answered him from Shittim unto Gilgal; that ye may know the righteousness of the LORD.","ref":"Micah 6:5","synthesized":"My people, remember what Balak king of Moab counseled and what Balaam son of Beor answered. Remember your journey from Shittim to Gilgal, so that you may acknowledge the righteousness of the LORD.’”","sources":{"KJV":{"text":"O my people, remember now what Balak king of Moab consulted, and what Balaam the son of Beor answered him from Shittim unto Gilgal; that ye may know the righteousness of the LORD."},"BSB":{"text":"My people, remember what Balak king of Moab counseled and what Balaam son of Beor answered. Remember your journey from Shittim to Gilgal, so that you may acknowledge the righteousness of the LORD.’”"}},"definableWords":["people","remember","king","son","righteousness","LORD"],"peopleInVerse":[]},"6":{"text":"Wherewith shall I come before the LORD, and bow myself before the high God? shall I come before him with burnt offerings, with calves of a year old?","ref":"Micah 6:6","synthesized":"With what shall I come before the LORD when I bow before the God on high? Should I come to Him with burnt offerings, with year-old calves?","sources":{"KJV":{"text":"Wherewith shall I come before the LORD, and bow myself before the high God? shall I come before him with burnt offerings, with calves of a year old?"},"BSB":{"text":"With what shall I come before the LORD when I bow before the God on high? Should I come to Him with burnt offerings, with year-old calves?"}},"definableWords":["LORD","God","year"],"peopleInVerse":[]},"7":{"text":"Will the LORD be pleased with thousands of rams, or with ten thousands of rivers of oil? shall I give my firstborn for my transgression, the fruit of my body for the sin of my soul?","ref":"Micah 6:7","synthesized":"Would the LORD be pleased with thousands of rams, with ten thousand rivers of oil? Shall I present my firstborn for my transgression, the fruit of my body for the sin of my soul?","sources":{"KJV":{"text":"Will the LORD be pleased with thousands of rams, or with ten thousands of rivers of oil? shall I give my firstborn for my transgression, the fruit of my body for the sin of my soul?"},"BSB":{"text":"Would the LORD be pleased with thousands of rams, with ten thousand rivers of oil? Shall I present my firstborn for my transgression, the fruit of my body for the sin of my soul?"}},"definableWords":["LORD","transgression","sin","soul"],"peopleInVerse":[]},"8":{"text":"He hath shewed thee, O man, what is good; and what doth the LORD require of thee, but to do justly, and to love mercy, and to walk humbly with thy God?","ref":"Micah 6:8","synthesized":"He has shown you, O man, what is good. And what does the LORD require of you but to act justly, to love mercy, and to walk humbly with your God?","sources":{"KJV":{"text":"He hath shewed thee, O man, what is good; and what doth the LORD require of thee, but to do justly, and to love mercy, and to walk humbly with thy God?"},"BSB":{"text":"He has shown you, O man, what is good. And what does the LORD require of you but to act justly, to love mercy, and to walk humbly with your God?"}},"definableWords":["man","good","LORD","love","mercy","walk","God"],"peopleInVerse":[]},"9":{"text":"The LORD’s voice crieth unto the city, and the man of wisdom shall see thy name: hear ye the rod, and who hath appointed it.","ref":"Micah 6:9","synthesized":"The voice of the LORD calls out to the city (and it is sound wisdom to fear Your name): “Heed the rod and the One who ordained it.","sources":{"KJV":{"text":"The LORD’s voice crieth unto the city, and the man of wisdom shall see thy name: hear ye the rod, and who hath appointed it."},"BSB":{"text":"The voice of the LORD calls out to the city (and it is sound wisdom to fear Your name): “Heed the rod and the One who ordained it."}},"definableWords":["voice","LORD","wisdom","fear","name","one"],"peopleInVerse":[]},"10":{"text":"Are there yet the treasures of wickedness in the house of the wicked, and the scant measure that is abominable?","ref":"Micah 6:10","synthesized":"Can I forget any longer, O house of the wicked, the treasures of wickedness and the short ephah, which is accursed?","sources":{"KJV":{"text":"Are there yet the treasures of wickedness in the house of the wicked, and the scant measure that is abominable?"},"BSB":{"text":"Can I forget any longer, O house of the wicked, the treasures of wickedness and the short ephah, which is accursed?"}},"definableWords":["house"],"peopleInVerse":[]},"11":{"text":"Shall I count them pure with the wicked balances, and with the bag of deceitful weights?","ref":"Micah 6:11","synthesized":"Can I excuse dishonest scales or bags of false weights?","sources":{"KJV":{"text":"Shall I count them pure with the wicked balances, and with the bag of deceitful weights?"},"BSB":{"text":"Can I excuse dishonest scales or bags of false weights?"}},"definableWords":["or"],"peopleInVerse":[]},"12":{"text":"For the rich men thereof are full of violence, and the inhabitants thereof have spoken lies, and their tongue is deceitful in their mouth.","ref":"Micah 6:12","synthesized":"For the wealthy of the city are full of violence, and its residents speak lies; their tongues are deceitful in their mouths.","sources":{"KJV":{"text":"For the rich men thereof are full of violence, and the inhabitants thereof have spoken lies, and their tongue is deceitful in their mouth."},"BSB":{"text":"For the wealthy of the city are full of violence, and its residents speak lies; their tongues are deceitful in their mouths."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Therefore also will I make thee sick in smiting thee, in making thee desolate because of thy sins.","ref":"Micah 6:13","synthesized":"Therefore I am striking you severely, to ruin you because of your sins.","sources":{"KJV":{"text":"Therefore also will I make thee sick in smiting thee, in making thee desolate because of thy sins."},"BSB":{"text":"Therefore I am striking you severely, to ruin you because of your sins."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Thou shalt eat, but not be satisfied; and thy casting down shall be in the midst of thee; and thou shalt take hold, but shalt not deliver; and that which thou deliverest will I give up to the sword.","ref":"Micah 6:14","synthesized":"You will eat but not be satisfied, and your hunger will remain with you. What you acquire, you will not preserve; and what you save, I will give to the sword.","sources":{"KJV":{"text":"Thou shalt eat, but not be satisfied; and thy casting down shall be in the midst of thee; and thou shalt take hold, but shalt not deliver; and that which thou deliverest will I give up to the sword."},"BSB":{"text":"You will eat but not be satisfied, and your hunger will remain with you. What you acquire, you will not preserve; and what you save, I will give to the sword."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Thou shalt sow, but thou shalt not reap; thou shalt tread the olives, but thou shalt not anoint thee with oil; and sweet wine, but shalt not drink wine.","ref":"Micah 6:15","synthesized":"You will sow but not reap; you will press olives but not anoint yourselves with oil; you will tread grapes but not drink the wine.","sources":{"KJV":{"text":"Thou shalt sow, but thou shalt not reap; thou shalt tread the olives, but thou shalt not anoint thee with oil; and sweet wine, but shalt not drink wine."},"BSB":{"text":"You will sow but not reap; you will press olives but not anoint yourselves with oil; you will tread grapes but not drink the wine."}},"definableWords":["anoint"],"peopleInVerse":[]},"16":{"text":"For the statutes of Omri are kept, and all the works of the house of Ahab, and ye walk in their counsels; that I should make thee a desolation, and the inhabitants thereof an hissing: therefore ye shall bear the reproach of my people.","ref":"Micah 6:16","synthesized":"You have kept the statutes of Omri and all the practices of Ahab’s house; you have followed their counsel. Therefore I will make you a desolation, and your inhabitants an object of contempt; you will bear the scorn of the nations.”","sources":{"KJV":{"text":"For the statutes of Omri are kept, and all the works of the house of Ahab, and ye walk in their counsels; that I should make thee a desolation, and the inhabitants thereof an hissing: therefore ye shall bear the reproach of my people."},"BSB":{"text":"You have kept the statutes of Omri and all the practices of Ahab’s house; you have followed their counsel. Therefore I will make you a desolation, and your inhabitants an object of contempt; you will bear the scorn of the nations.”"}},"definableWords":["house","make","nations"],"peopleInVerse":[]}}},"7":{"chapter":"7","title":"WHO IS A GOD LIKE UNTO THEE?","verses":{"1":{"text":"Woe is me! for I am as when they have gathered the summer fruits, as the grapegleanings of the vintage: there is no cluster to eat: my soul desired the firstripe fruit.","ref":"Micah 7:1","synthesized":"Woe is me!   For I am like one gathering summer fruit at the gleaning of the vineyard; there is no cluster to eat, no early fig that I crave.","sources":{"KJV":{"text":"Woe is me! for I am as when they have gathered the summer fruits, as the grapegleanings of the vintage: there is no cluster to eat: my soul desired the firstripe fruit."},"BSB":{"text":"Woe is me!   For I am like one gathering summer fruit at the gleaning of the vineyard; there is no cluster to eat, no early fig that I crave."}},"definableWords":["one"],"peopleInVerse":[]},"2":{"text":"The good man is perished out of the earth: and there is none upright among men: they all lie in wait for blood; they hunt every man his brother with a net.","ref":"Micah 7:2","synthesized":"The godly man has perished from the earth; there is no one upright among men. They all lie in wait for blood; they hunt one another with a net.","sources":{"KJV":{"text":"The good man is perished out of the earth: and there is none upright among men: they all lie in wait for blood; they hunt every man his brother with a net."},"BSB":{"text":"The godly man has perished from the earth; there is no one upright among men. They all lie in wait for blood; they hunt one another with a net."}},"definableWords":["man","earth","one","men","wait","blood"],"peopleInVerse":[]},"3":{"text":"That they may do evil with both hands earnestly, the prince asketh, and the judge asketh for a reward; and the great man, he uttereth his mischievous desire: so they wrap it up.","ref":"Micah 7:3","synthesized":"Both hands are skilled at evil; the prince and the judge demand a bribe. When the powerful utters his evil desire, they all conspire together.","sources":{"KJV":{"text":"That they may do evil with both hands earnestly, the prince asketh, and the judge asketh for a reward; and the great man, he uttereth his mischievous desire: so they wrap it up."},"BSB":{"text":"Both hands are skilled at evil; the prince and the judge demand a bribe. When the powerful utters his evil desire, they all conspire together."}},"definableWords":["evil","prince"],"peopleInVerse":[]},"4":{"text":"The best of them is as a brier: the most upright is sharper than a thorn hedge: the day of thy watchmen and thy visitation cometh; now shall be their perplexity.","ref":"Micah 7:4","synthesized":"The best of them is like a brier; the most upright is sharper than a hedge of thorns. The day for your watchmen has come, the day of your visitation. Now is the time of their confusion.","sources":{"KJV":{"text":"The best of them is as a brier: the most upright is sharper than a thorn hedge: the day of thy watchmen and thy visitation cometh; now shall be their perplexity."},"BSB":{"text":"The best of them is like a brier; the most upright is sharper than a hedge of thorns. The day for your watchmen has come, the day of your visitation. Now is the time of their confusion."}},"definableWords":["day"],"peopleInVerse":[]},"5":{"text":"Trust ye not in a friend, put ye not confidence in a guide: keep the doors of thy mouth from her that lieth in thy bosom.","ref":"Micah 7:5","synthesized":"Do not rely on a friend; do not trust in a companion. Seal the doors of your mouth from her who lies in your arms.","sources":{"KJV":{"text":"Trust ye not in a friend, put ye not confidence in a guide: keep the doors of thy mouth from her that lieth in thy bosom."},"BSB":{"text":"Do not rely on a friend; do not trust in a companion. Seal the doors of your mouth from her who lies in your arms."}},"definableWords":["trust"],"peopleInVerse":[]},"6":{"text":"For the son dishonoureth the father, the daughter riseth up against her mother, the daughter in law against her mother in law; a man’s enemies are the men of his own house.","ref":"Micah 7:6","synthesized":"For a son dishonors his father, a daughter rises against her mother, and a daughter-in-law against her mother-in-law. A man’s enemies are the members of his own household.","sources":{"KJV":{"text":"For the son dishonoureth the father, the daughter riseth up against her mother, the daughter in law against her mother in law; a man’s enemies are the men of his own house."},"BSB":{"text":"For a son dishonors his father, a daughter rises against her mother, and a daughter-in-law against her mother-in-law. A man’s enemies are the members of his own household."}},"definableWords":["son","father","daughter","mother","law","man"],"peopleInVerse":[]},"7":{"text":"Therefore I will look unto the LORD; I will wait for the God of my salvation: my God will hear me.","ref":"Micah 7:7","synthesized":"But as for me, I will look to the LORD; I will wait for the God of my salvation. My God will hear me.","sources":{"KJV":{"text":"Therefore I will look unto the LORD; I will wait for the God of my salvation: my God will hear me."},"BSB":{"text":"But as for me, I will look to the LORD; I will wait for the God of my salvation. My God will hear me."}},"definableWords":["LORD","wait","God","salvation","hear"],"peopleInVerse":[]},"8":{"text":"Rejoice not against me, O mine enemy: when I fall, I shall arise; when I sit in darkness, the LORD shall be a light unto me.","ref":"Micah 7:8","synthesized":"Do not gloat over me, my enemy! Though I have fallen, I will arise; though I sit in darkness, the LORD will be my light.","sources":{"KJV":{"text":"Rejoice not against me, O mine enemy: when I fall, I shall arise; when I sit in darkness, the LORD shall be a light unto me."},"BSB":{"text":"Do not gloat over me, my enemy! Though I have fallen, I will arise; though I sit in darkness, the LORD will be my light."}},"definableWords":["darkness","LORD","light"],"peopleInVerse":[]},"9":{"text":"I will bear the indignation of the LORD, because I have sinned against him, until he plead my cause, and execute judgment for me: he will bring me forth to the light, and I shall behold his righteousness.","ref":"Micah 7:9","synthesized":"Because I have sinned against Him, I must endure the rage of the LORD, until He argues my case and executes justice for me. He will bring me into the light; I will see His righteousness.","sources":{"KJV":{"text":"I will bear the indignation of the LORD, because I have sinned against him, until he plead my cause, and execute judgment for me: he will bring me forth to the light, and I shall behold his righteousness."},"BSB":{"text":"Because I have sinned against Him, I must endure the rage of the LORD, until He argues my case and executes justice for me. He will bring me into the light; I will see His righteousness."}},"definableWords":["LORD","justice","light","see","righteousness"],"peopleInVerse":[]},"10":{"text":"Then she that is mine enemy shall see it, and shame shall cover her which said unto me, Where is the LORD thy God? mine eyes shall behold her: now shall she be trodden down as the mire of the streets.","ref":"Micah 7:10","synthesized":"Then my enemy will see and will be covered with shame— she who said to me, “Where is the LORD your God?” My eyes will see her; at that time she will be trampled like mud in the streets.","sources":{"KJV":{"text":"Then she that is mine enemy shall see it, and shame shall cover her which said unto me, Where is the LORD thy God? mine eyes shall behold her: now shall she be trodden down as the mire of the streets."},"BSB":{"text":"Then my enemy will see and will be covered with shame— she who said to me, “Where is the LORD your God?” My eyes will see her; at that time she will be trampled like mud in the streets."}},"definableWords":["see","LORD","God"],"peopleInVerse":[]},"11":{"text":"In the day that thy walls are to be built, in that day shall the decree be far removed.","ref":"Micah 7:11","synthesized":"The day for rebuilding your walls will come— the day for extending your boundary.","sources":{"KJV":{"text":"In the day that thy walls are to be built, in that day shall the decree be far removed."},"BSB":{"text":"The day for rebuilding your walls will come— the day for extending your boundary."}},"definableWords":["day"],"peopleInVerse":[]},"12":{"text":"In that day also he shall come even to thee from Assyria, and from the fortified cities, and from the fortress even to the river, and from sea to sea, and from mountain to mountain.","ref":"Micah 7:12","synthesized":"On that day they will come to you from Assyria and the cities of Egypt, even from Egypt to the Euphrates, from sea to sea and mountain to mountain.","sources":{"KJV":{"text":"In that day also he shall come even to thee from Assyria, and from the fortified cities, and from the fortress even to the river, and from sea to sea, and from mountain to mountain."},"BSB":{"text":"On that day they will come to you from Assyria and the cities of Egypt, even from Egypt to the Euphrates, from sea to sea and mountain to mountain."}},"definableWords":["day","Egypt","sea"],"peopleInVerse":[]},"13":{"text":"Notwithstanding the land shall be desolate because of them that dwell therein, for the fruit of their doings.","ref":"Micah 7:13","synthesized":"Then the earth will become desolate because of its inhabitants, as the fruit of their deeds.","sources":{"KJV":{"text":"Notwithstanding the land shall be desolate because of them that dwell therein, for the fruit of their doings."},"BSB":{"text":"Then the earth will become desolate because of its inhabitants, as the fruit of their deeds."}},"definableWords":["earth"],"peopleInVerse":[]},"14":{"text":"Feed thy people with thy rod, the flock of thine heritage, which dwell solitarily in the wood, in the midst of Carmel: let them feed in Bashan and Gilead, as in the days of old.","ref":"Micah 7:14","synthesized":"Shepherd with Your staff Your people, the flock of Your inheritance. They live alone in a woodland, surrounded by pastures. Let them graze in Bashan and Gilead, as in the days of old.","sources":{"KJV":{"text":"Feed thy people with thy rod, the flock of thine heritage, which dwell solitarily in the wood, in the midst of Carmel: let them feed in Bashan and Gilead, as in the days of old."},"BSB":{"text":"Shepherd with Your staff Your people, the flock of Your inheritance. They live alone in a woodland, surrounded by pastures. Let them graze in Bashan and Gilead, as in the days of old."}},"definableWords":["shepherd","people","live","days"],"peopleInVerse":[]},"15":{"text":"According to the days of thy coming out of the land of Egypt will I shew unto him marvellous things.","ref":"Micah 7:15","synthesized":"As in the days when you came out of Egypt, I will show My wonders.","sources":{"KJV":{"text":"According to the days of thy coming out of the land of Egypt will I shew unto him marvellous things."},"BSB":{"text":"As in the days when you came out of Egypt, I will show My wonders."}},"definableWords":["days","Egypt"],"peopleInVerse":[]},"16":{"text":"The nations shall see and be confounded at all their might: they shall lay their hand upon their mouth, their ears shall be deaf.","ref":"Micah 7:16","synthesized":"Nations will see and be ashamed, deprived of all their might. They will put their hands over their mouths, and their ears will become deaf.","sources":{"KJV":{"text":"The nations shall see and be confounded at all their might: they shall lay their hand upon their mouth, their ears shall be deaf."},"BSB":{"text":"Nations will see and be ashamed, deprived of all their might. They will put their hands over their mouths, and their ears will become deaf."}},"definableWords":["nations","see"],"peopleInVerse":[]},"17":{"text":"They shall lick the dust like a serpent, they shall move out of their holes like worms of the earth: they shall be afraid of the LORD our God, and shall fear because of thee.","ref":"Micah 7:17","synthesized":"They will lick the dust like a snake, like reptiles slithering on the ground. They will crawl from their holes in the presence of the LORD our God; they will tremble in fear of You.","sources":{"KJV":{"text":"They shall lick the dust like a serpent, they shall move out of their holes like worms of the earth: they shall be afraid of the LORD our God, and shall fear because of thee."},"BSB":{"text":"They will lick the dust like a snake, like reptiles slithering on the ground. They will crawl from their holes in the presence of the LORD our God; they will tremble in fear of You."}},"definableWords":["ground","LORD","God","fear"],"peopleInVerse":[]},"18":{"text":"Who is a God like unto thee, that pardoneth iniquity, and passeth by the transgression of the remnant of his heritage? he retaineth not his anger for ever, because he delighteth in mercy.","ref":"Micah 7:18","synthesized":"Who is a God like You, who pardons iniquity and passes over the transgression of the remnant of His inheritance— who does not retain His anger forever, because He delights in loving devotion?","sources":{"KJV":{"text":"Who is a God like unto thee, that pardoneth iniquity, and passeth by the transgression of the remnant of his heritage? he retaineth not his anger for ever, because he delighteth in mercy."},"BSB":{"text":"Who is a God like You, who pardons iniquity and passes over the transgression of the remnant of His inheritance— who does not retain His anger forever, because He delights in loving devotion?"}},"definableWords":["God","iniquity","transgression","remnant","anger"],"peopleInVerse":[]},"19":{"text":"He will turn again, he will have compassion upon us; he will subdue our iniquities; and thou wilt cast all their sins into the depths of the sea.","ref":"Micah 7:19","synthesized":"He will again have compassion on us; He will vanquish our iniquities. You will cast out all our sins into the depths of the sea.","sources":{"KJV":{"text":"He will turn again, he will have compassion upon us; he will subdue our iniquities; and thou wilt cast all their sins into the depths of the sea."},"BSB":{"text":"He will again have compassion on us; He will vanquish our iniquities. You will cast out all our sins into the depths of the sea."}},"definableWords":["sea"],"peopleInVerse":[]},"20":{"text":"Thou wilt perform the truth to Jacob, and the mercy to Abraham, which thou hast sworn unto our fathers from the days of old.","ref":"Micah 7:20","synthesized":"You will show faithfulness to Jacob and loving devotion to Abraham, as You swore to our fathers from the days of old.","sources":{"KJV":{"text":"Thou wilt perform the truth to Jacob, and the mercy to Abraham, which thou hast sworn unto our fathers from the days of old."},"BSB":{"text":"You will show faithfulness to Jacob and loving devotion to Abraham, as You swore to our fathers from the days of old."}},"definableWords":["Jacob","Abraham","fathers","days"],"peopleInVerse":["Jacob","Abraham"]}}}};